import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

import { profileApi, type ProfileResponse } from '../api/profile';
import { groupsApi, type GroupResponse } from '../api/groups';
import { requestsApi } from '../api/requests';
import { Card, Avatar, Badge, Button, Loading } from '../components/common';
import {
    Users,
    MessageSquare,
    Star,
    ChevronRight,
    UserPlus,
    Bell,
    Zap
} from 'lucide-react';

export const Dashboard: React.FC = () => {
    const navigate = useNavigate();

    const [profile, setProfile] = useState<ProfileResponse | null>(null);
    const [recommendedGroups, setRecommendedGroups] = useState<GroupResponse[]>([]);

    const [pendingRequests, setPendingRequests] = useState<any[]>([]);
    const [unreadMessages, setUnreadMessages] = useState(0);
    const [recentActivity, setRecentActivity] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [stats, setStats] = useState({
        totalGroups: 0,
        totalConnections: 0,
        totalStars: 0,
        teamCompatibility: 0
    });

    useEffect(() => {
        loadDashboardData();
    }, []);

    const loadDashboardData = async () => {
        setLoading(true);
        try {
            // Load profile data
            const profileData = await profileApi.getMyProfile();
            setProfile(profileData);

            // Load user's groups
            const groups = await groupsApi.getMyGroups();
            setRecommendedGroups(groups.slice(0, 3));

            // Load pending requests
            const received = await requestsApi.getReceivedRequests('pending');
            setPendingRequests(received);

            // Load connections count
            const connections = await requestsApi.getConnections();

            // Load unread messages (if you have chat API)
            // const unread = await chatApi.getUnreadCount();
            // setUnreadMessages(unread.unread_count);

            // Calculate stats
            setStats({
                totalGroups: groups.length,
                totalConnections: connections.length,
                totalStars: profileData.repository_analysis.total_stars,
                teamCompatibility: 85 // Placeholder - calculate based on team formation
            });

            // Generate recent activity (mock for now)
            setRecentActivity([
                {
                    id: '1',
                    type: 'connection',
                    message: 'You connected with John Doe',
                    time: '2 hours ago',
                    icon: <UserPlus className="w-4 h-4" />
                },
                {
                    id: '2',
                    type: 'group',
                    message: 'New message in Project Alpha',
                    time: '5 hours ago',
                    icon: <MessageSquare className="w-4 h-4" />
                },
                {
                    id: '3',
                    type: 'request',
                    message: 'Jane Smith sent you a connection request',
                    time: '1 day ago',
                    icon: <Bell className="w-4 h-4" />
                }
            ]);

        } catch (error) {
            console.error('Failed to load dashboard data:', error);
        } finally {
            setLoading(false);
        }
    };

    if (loading) {
        return <Loading fullScreen text="Loading dashboard..." />;
    }

    const quickActions = [
        {
            id: 'find-team',
            label: 'Find Team',
            icon: <Users className="w-5 h-5" />,
            onClick: () => navigate('/team'),
            color: 'bg-blue-500'
        },
        {
            id: 'join-group',
            label: 'Join Group',
            icon: <Users className="w-5 h-5" />,
            onClick: () => navigate('/groups'),
            color: 'bg-green-500'
        },
        {
            id: 'view-requests',
            label: 'Requests',
            icon: <Bell className="w-5 h-5" />,
            onClick: () => navigate('/requests'),
            color: 'bg-purple-500',
            badge: pendingRequests.length
        },
        {
            id: 'start-chat',
            label: 'Messages',
            icon: <MessageSquare className="w-5 h-5" />,
            onClick: () => navigate('/chat'),
            color: 'bg-indigo-500',
            badge: unreadMessages
        }
    ];

    const statCards = [
        {
            id: 'groups',
            label: 'Groups',
            value: stats.totalGroups,
            icon: <Users className="w-6 h-6" />,
            color: 'bg-indigo-100 text-indigo-600'
        },
        {
            id: 'connections',
            label: 'Connections',
            value: stats.totalConnections,
            icon: <UserPlus className="w-6 h-6" />,
            color: 'bg-green-100 text-green-600'
        },
        {
            id: 'stars',
            label: 'GitHub Stars',
            value: stats.totalStars,
            icon: <Star className="w-6 h-6" />,
            color: 'bg-yellow-100 text-yellow-600'
        },
        {
            id: 'compatibility',
            label: 'Team Compatibility',
            value: `${stats.teamCompatibility}%`,
            icon: <Zap className="w-6 h-6" />,
            color: 'bg-purple-100 text-purple-600'
        }
    ];

    return (
        <div className="dashboard min-h-screen bg-gray-50">
            {/* Welcome Section */}
            <div className="bg-white border-b border-gray-200">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <Avatar
                                src={profile?.github_profile.avatar_url}
                                username={profile?.github_profile.login}
                                size="lg"
                            />
                            <div>
                                <h1 className="text-2xl font-bold text-gray-900">
                                    Welcome back, {profile?.github_profile.name || profile?.github_profile.login}!
                                </h1>
                                <p className="text-gray-600">
                                    {profile?.github_profile.bio || 'Ready to collaborate?'}
                                </p>
                            </div>
                        </div>
                        <Button
                            variant="outline"
                            onClick={() => navigate('/profile')}
                            icon={<ChevronRight className="w-4 h-4" />}
                            iconPosition="right"
                        >
                            View Profile
                        </Button>
                    </div>
                </div>
            </div>

            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
                {/* Quick Actions */}
                <div className="mb-8">
                    <h2 className="text-lg font-semibold text-gray-900 mb-4">Quick Actions</h2>
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                        {quickActions.map(action => (
                            <button
                                key={action.id}
                                onClick={action.onClick}
                                className="relative p-6 bg-white rounded-xl shadow-sm hover:shadow-md transition-shadow border border-gray-100"
                            >
                                <div className={`w-12 h-12 ${action.color} rounded-lg flex items-center justify-center text-white mb-3`}>
                                    {action.icon}
                                </div>
                                <h3 className="font-medium text-gray-900">{action.label}</h3>
                                {action.badge ? (
                                    <Badge
                                        count={action.badge}
                                        className="absolute top-3 right-3"
                                    />
                                ) : null}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Stats Grid */}
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
                    {statCards.map(stat => (
                        <Card key={stat.id} className="hover:shadow-md transition-shadow">
                            <div className="flex items-center justify-between">
                                <div>
                                    <p className="text-sm text-gray-500 mb-1">{stat.label}</p>
                                    <p className="text-2xl font-bold text-gray-900">{stat.value}</p>
                                </div>
                                <div className={`w-12 h-12 ${stat.color} rounded-lg flex items-center justify-center`}>
                                    {stat.icon}
                                </div>
                            </div>
                        </Card>
                    ))}
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                    {/* Left Column */}
                    <div className="lg:col-span-2 space-y-8">
                        {/* Recent Activity */}
                        <Card title="Recent Activity">
                            <div className="space-y-4">
                                {recentActivity.map(activity => (
                                    <div key={activity.id} className="flex items-start gap-3">
                                        <div className="w-8 h-8 bg-gray-100 rounded-full flex items-center justify-center">
                                            {activity.icon}
                                        </div>
                                        <div className="flex-1">
                                            <p className="text-sm text-gray-800">{activity.message}</p>
                                            <p className="text-xs text-gray-400">{activity.time}</p>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </Card>

                        {/* Your Groups */}
                        <Card
                            title="Your Groups"
                            headerAction={
                                <Button
                                    variant="ghost"
                                    size="sm"
                                    onClick={() => navigate('/groups')}
                                    icon={<ChevronRight className="w-4 h-4" />}
                                    iconPosition="right"
                                >
                                    View All
                                </Button>
                            }
                        >
                            <div className="space-y-4">
                                {recommendedGroups.length > 0 ? (
                                    recommendedGroups.map(group => (
                                        <button
                                            key={group.id}
                                            onClick={() => navigate(`/groups/${group.id}`)}
                                            className="w-full flex items-center gap-3 p-3 hover:bg-gray-50 rounded-lg transition-colors"
                                        >
                                            <Avatar
                                                username={group.name}
                                                size="md"
                                            />
                                            <div className="flex-1 text-left">
                                                <h4 className="text-sm font-medium text-gray-900">{group.name}</h4>
                                                <p className="text-xs text-gray-500">
                                                    {group.member_count} members ΓÇó {group.online_count} online
                                                </p>
                                            </div>
                                            {group.unread_count > 0 && (
                                                <Badge count={group.unread_count} />
                                            )}
                                        </button>
                                    ))
                                ) : (
                                    <p className="text-sm text-gray-500 text-center py-4">
                                        You haven't joined any groups yet
                                    </p>
                                )}
                            </div>
                        </Card>
                    </div>

                    {/* Right Column */}
                    <div className="space-y-8">
                        {/* Profile Overview */}
                        <Card title="Profile Overview">
                            <div className="space-y-4">
                                <div className="flex items-center justify-between">
                                    <span className="text-sm text-gray-500">GitHub</span>
                                    <span className="text-sm font-medium">@{profile?.github_profile.login}</span>
                                </div>
                                <div className="flex items-center justify-between">
                                    <span className="text-sm text-gray-500">Repositories</span>
                                    <span className="text-sm font-medium">{profile?.repository_analysis.total_repositories}</span>
                                </div>
                                <div className="flex items-center justify-between">
                                    <span className="text-sm text-gray-500">Followers</span>
                                    <span className="text-sm font-medium">{profile?.github_profile.followers}</span>
                                </div>
                                <div className="flex items-center justify-between">
                                    <span className="text-sm text-gray-500">Following</span>
                                    <span className="text-sm font-medium">{profile?.github_profile.following}</span>
                                </div>
                                <div className="pt-2">
                                    <h4 className="text-sm font-medium text-gray-900 mb-2">Top Skills</h4>
                                    <div className="flex flex-wrap gap-2">
                                        {Object.entries(profile?.estimated_skills || {})
                                            .sort(([, a], [, b]) => b - a)
                                            .slice(0, 5)
                                            .map(([skill, level]) => (
                                                <Badge key={skill} variant="primary">
                                                    {skill} {level}/5
                                                </Badge>
                                            ))}
                                    </div>
                                </div>
                            </div>
                        </Card>

                        {/* Pending Requests */}
                        {pendingRequests.length > 0 && (
                            <Card title="Pending Requests">
                                <div className="space-y-3">
                                    {pendingRequests.slice(0, 3).map(request => (
                                        <div key={request.id} className="flex items-center gap-3">
                                            <Avatar
                                                username={request.sender_username}
                                                size="sm"
                                            />
                                            <div className="flex-1">
                                                <p className="text-sm text-gray-900">{request.sender_username}</p>
                                                <p className="text-xs text-gray-500">wants to connect</p>
                                            </div>
                                            <Button
                                                size="xs"
                                                variant="success"
                                                onClick={() => navigate('/requests')}
                                            >
                                                View
                                            </Button>
                                        </div>
                                    ))}
                                    {pendingRequests.length > 3 && (
                                        <button
                                            onClick={() => navigate('/requests')}
                                            className="text-xs text-indigo-600 hover:text-indigo-800 mt-2"
                                        >
                                            +{pendingRequests.length - 3} more requests
                                        </button>
                                    )}
                                </div>
                            </Card>
                        )}

                        {/* Team Formation Suggestion */}
                        <Card title="Team Formation">
                            <div className="text-center py-4">
                                <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center mx-auto mb-3">
                                    <Users className="w-8 h-8 text-indigo-600" />
                                </div>
                                <h3 className="text-sm font-medium text-gray-900 mb-1">
                                    Build Your Dream Team
                                </h3>
                                <p className="text-xs text-gray-500 mb-4">
                                    Find teammates with complementary skills
                                </p>
                                <Button
                                    size="sm"
                                    onClick={() => navigate('/team')}
                                >
                                    Start Building
                                </Button>
                            </div>
                        </Card>
                    </div>
                </div>
            </div>
        </div>
    );
};
